import sys
import numpy as np
from pathlib import Path

import logging
logger = logging.getLogger(__name__)

class Result:
    """
    Reader for ALAMODE ``*.result`` files.

    Parameters
    ----------
    filename : str or os.PathLike or None, optional
        Path to the ``*.result`` file. If ``None``, an empty container is created.

    Attributes
    ----------
    frequencies : numpy.ndarray of float, shape (n_kpoints, n_bands)
        Phonon eigenvalues (frequencies).
    general : General
        Information parsed from the ``#General`` section.
    multiplicity : numpy.ndarray of int, shape (n_kpoints,)
        Mode multiplicity per k-point.
    velocities : numpy.ndarray of float, shape (n_kpoints, n_bands, m_max, 3)
        Group velocities.
    gammas : numpy.ndarray of float, shape (n_temps, n_kpoints, n_bands)
        Scattering rates.
    kmode : numpy.ndarray of float, shape (n_temps, n_kpoints, n_bands, m_max, 3, 3)
        Mode-resolved thermal-conductivity tensor.
    lmode : numpy.ndarray of float, shape (n_temps, n_kpoints, n_bands, m_max, 3)
        Mode-resolved mean free path.

    Notes
    -----
    - Use literal markup (double backticks) for patterns like ``*.result`` to
      avoid unintended emphasis in reStructuredText.
    """
    def __init__(self, filename=None):
        """ Initialize the container and optionally read a ``*.result`` file.
        """
        self._values = None
        self.filename = filename
        
        self._lifetime = None
        
        if self.filename is not None:
            self.set_result()
    
    def __str__(self):
        if self._values is None:
            return "\n Result file: %s (not loaded)" % self.filename
        keys = list(self._values.keys())
        msg = "\n Result file: %s" % self.filename
        msg += "\n"
        for k1 in keys:
            msg += "\n %s " % k1
            if isinstance(self._values[k1], dict):
                for k2 in self._values[k1]:
                    msg += "\n  |--- %13s : " % k2
                    if isinstance(self._values[k1][k2], int):
                        msg += "%d" % self._values[k1][k2]
                    elif isinstance(self._values[k1][k2], float):
                        msg += "%f" % self._values[k1][k2]
                    elif isinstance(self._values[k1][k2], str):
                        msg += "%s" % self._values[k1][k2]
                    elif isinstance(self._values[k1][k2], np.ndarray):
                        msg += "%s" % str(self._values[k1][k2].shape)
                    else:
                        msg += " %s" % type(self._values[k1][k2])
        return msg
        
    def __getitem__(self, key):
        if self._values is None:
            return None
        for k1 in self._values:
            if k1 == key:
                return self._values[k1]
            for k2 in self._values[k1]:
                if k2 == key:
                    return self._values[k1][k2]
        
        msg = "\n Warning: %s cannot be found.\n" % key
        logger.warning(msg)
        return None
    
    def set_result(self):
        """
        Read self.filename and set class
        """
        if self.filename is None:
            logger.error(" Error: filename (*.result file) must be given.")
            sys.exit()
        
        try:
            self._values = read_result_file(self.filename)
        except Exception:
            fn_rel = Path(self.filename).relative_to(Path.cwd())
            line = f"Error: cannot read {fn_rel} properly."
            msg = "\n " + "#" * (len(line) + 2)
            msg += f"\n {line}"
            msg += "\n"
            msg += "\n Possible solution for this issue is"
            msg += f"\n * to delete {fn_rel} and"
            msg += "\n * to calculate thermal conductivity again."
            msg += "\n " + "#" * (len(line) + 2)
            logger.error(msg)
        
    def get_free_energy(self, temperatures):
        """Calcualte free enrgy
        Args
        -----
        temmperatures : array, float, shape=(nt)
            list of temperatures
        """
        return _get_free_energy(
                self.natoms,
                self.volume,
                self.temperatures,
                self.multiplicity, 
                self.frequencies)
    
